mapper.update:
UPDATE
    ESG.TB_RESULT_OF_RISK_ASSESSMENT_TRAINING
SET ASMNT_DATE       = #{asmntDate},
    ASMNT_START_TIME = #{asmntStartTime},
    ASMNT_END_TIME   = #{asmntEndTime},
    ASMNT_PLACE      = #{asmntPlace},
    ASMNT_CONTENT    = #{asmntContent},
    USE_YN           = #{useYn},
    UPDATED_AT       = NOW(),
    UPDATED_BY       = #{updatedBy}
WHERE WRITE_YEAR = #{writeYear}
  AND DOC_TYPE = #{docType}
  AND DOC_NO = #{docNo}

mapper.delete:
UPDATE
    ESG.tb_result_of_risk_assessment_training
SET USE_YN     = 'N',
    UPDATED_AT = NOW(),
    UPDATED_BY = #{updatedBy}
WHERE WRITE_YEAR = #{writeYear}
  AND DOC_TYPE = #{docType}
  AND DOC_NO = #{docNo}
